<section class="content-header"><h1>Leave Utilisation</h1><ol class="breadcrumb"><li>Reports</li><li class="active">Leave</li></ol></section>
<section class="content">
<div class="box box-default"><div class="box-body"><div class="row"><div class="col-md-3"><div class="form-group"><label>Year</label><select id="year-filter" class="form-control"><?php for($y=date('Y');$y>=date('Y')-2;$y--): ?><option <?= $y==date('Y')?'selected':'' ?>><?= $y ?></option><?php endfor; ?></select></div></div><div class="col-md-2" style="padding-top:25px"><button class="btn btn-primary" id="btn-filter">Filter</button></div></div></div></div>
<div class="box box-info"><div class="box-header with-border"><h3 class="box-title">Leave Balances</h3></div><div class="box-body"><table class="table table-bordered"><thead><tr><th>Staff</th><th>Type</th><th>Total</th><th>Used</th><th>Pending</th><th>Available</th></tr></thead><tbody id="leave-util-body"><tr><td colspan="6" class="text-center text-muted">Apply filter</td></tr></tbody></table></div></div>
</section>
<script>function loadReport(){$.getJSON(BASE_URL+'reports/leave_data',{year:$('#year-filter').val()},function(res){var html='';$.each(res.data||[],function(i,r){var avail=r.total_days-r.used_days-r.pending_days;html+='<tr><td>'+CRM.esc(r.staff_name)+'</td><td>'+CRM.esc(r.leave_type)+'</td><td>'+r.total_days+'</td><td>'+r.used_days+'</td><td>'+r.pending_days+'</td><td><strong>'+avail+'</strong></td></tr>';});$('#leave-util-body').html(html||'<tr><td colspan="6" class="text-center text-muted">No data</td></tr>');});}
$('#btn-filter').click(loadReport);</script>
